t_020_ecs.llm_output:
using SpacetimeDB;

public static partial class Module
{
    [SpacetimeDB.Table(Name = "Entity", Public = true)]
    public partial struct Entity
    {
        [SpacetimeDB.PrimaryKey]
        public int Id;
    }

    [SpacetimeDB.Table(Name = "Position", Public = true)]
    public partial struct Position
    {
        [SpacetimeDB.PrimaryKey]
        public int EntityId;
        public int X;
        public int Y;
    }

    [SpacetimeDB.Table(Name = "Velocity", Public = true)]
    public partial struct Velocity
    {
        [SpacetimeDB.PrimaryKey]
        public int EntityId;
        public int VX;
        public int VY;
    }

    [SpacetimeDB.Table(Name = "NextPosition", Public = true)]
    public partial struct NextPosition
    {
        [SpacetimeDB.PrimaryKey]
        public int EntityId;
        public int X;
        public int Y;
    }

    [SpacetimeDB.Reducer]
    public static void Seed(ReducerContext ctx)
    {
        ctx.Db.Entity.Insert(new Entity { Id = 1 });
        ctx.Db.Position.Insert(new Position { EntityId = 1, X = 0, Y = 0 });
        ctx.Db.Velocity.Insert(new Velocity { EntityId = 1, VX = 1, VY = 0 });

        ctx.Db.Entity.Insert(new Entity { Id = 2 });
        ctx.Db.Position.Insert(new Position { EntityId = 2, X = 10, Y = 0 });
        ctx.Db.Velocity.Insert(new Velocity { EntityId = 2, VX = -2, VY = 3 });
    }

    [SpacetimeDB.Reducer]
    public static void Step(ReducerContext ctx)
    {
        foreach (var pos in ctx.Db.Position.Iter())
        {
            if (ctx.Db.Velocity.EntityId.Find(pos.EntityId) is Velocity vel)
            {
                var newX = pos.X + vel.VX;
                var newY = pos.Y + vel.VY;

                if (ctx.Db.NextPosition.EntityId.Find(pos.EntityId) is NextPosition existing)
                {
                    existing.X = newX;
                    existing.Y = newY;
                    ctx.Db.NextPosition.EntityId.Update(existing);
                }
                else
                {
                    ctx.Db.NextPosition.Insert(new NextPosition
                    {
                        EntityId = pos.EntityId,
                        X = newX,
                        Y = newY
                    });
                }
            }
        }
    }
}

