use spacetimedb::{ReducerContext, Table};

#[spacetimedb::table(accessor = entity, public)]
pub struct Entity {
    #[primary_key]
    id: i32,
}

#[spacetimedb::table(accessor = position, public)]
pub struct Position {
    #[primary_key]
    entity_id: i32,
    x: i32,
    y: i32,
}

#[spacetimedb::table(accessor = velocity, public)]
pub struct Velocity {
    #[primary_key]
    entity_id: i32,
    vx: i32,
    vy: i32,
}

#[spacetimedb::table(accessor = next_position, public)]
pub struct NextPosition {
    #[primary_key]
    entity_id: i32,
    x: i32,
    y: i32,
}

#[spacetimedb::reducer]
pub fn seed(ctx: &ReducerContext) -> Result<(), String> {
    ctx.db.entity().insert(Entity { id: 1 });
    ctx.db.entity().insert(Entity { id: 2 });

    ctx.db.position().insert(Position {
        entity_id: 1,
        x: 0,
        y: 0,
    });
    ctx.db.velocity().insert(Velocity {
        entity_id: 1,
        vx: 1,
        vy: 0,
    });

    ctx.db.position().insert(Position {
        entity_id: 2,
        x: 10,
        y: 0,
    });
    ctx.db.velocity().insert(Velocity {
        entity_id: 2,
        vx: -2,
        vy: 3,
    });

    Ok(())
}

#[spacetimedb::reducer]
pub fn step(ctx: &ReducerContext) -> Result<(), String> {
    for position in ctx.db.position().iter() {
        if let Some(vel) = ctx.db.velocity().entity_id().find(&position.entity_id) {
            let new_x = position.x + vel.vx;
            let new_y = position.y + vel.vy;
            ctx.db.next_position().entity_id().update(NextPosition {
                entity_id: position.entity_id,
                x: new_x,
                y: new_y,
            });
        }
    }
    Ok(())
}

