use spacetimedb::{ReducerContext, table};

#[spacetimedb(table(accessor = player, public))]
pub struct Player {
    #[primary_key]
    #[auto_inc]
    id: u64,
    name: String,
    score: u64,
}

#[spacetimedb(table(accessor = leaderboard, public))]
pub struct LeaderboardEntry {
    #[primary_key]
    rank: u32,
    player_name: String,
    score: u64,
}

#[spacetimedb(reducer)]
pub fn build_leaderboard(ctx: ReducerContext, limit: u32) -> Result<(), String> {
    // Clear existing leaderboard
    for entry in ctx.db.leaderboard().iter() {
        ctx.db.leaderboard().delete(entry);
    }

    // Collect and sort players
    let mut players: Vec<Player> = ctx.db.player().iter().collect();
    players.sort_by(|a, b| b.score.cmp(&a.score));
    players.truncate(limit as usize);

    // Insert ranked entries
    for (idx, player)) in players.into_iter().enumerate() {
        ctx.db.leaderboard().insert(LeaderboardEntry {
            rank: (idx + 1) as u32,
            player_name: player.name,
            score: player.score,
        })?;
    }

    Ok(())
}

