use spacetimedb::{ReducerContext, spacetimedb};

#[spacetimedb::table(name = entities, public)]
pub struct Entity {
    #[primary_key]
    id: i32,
}

#[spacetimedb::table(name = positions, public)]
pub struct Position {
    #[primary_key]
    entity_id: i32,
    x: i32,
    y: i32,
}

#[spacetimedb::table(name = velocities, public)]
pub struct Velocity {
    #[primary_key]
    entity_id: i32,
    vx: i32,
    vy: i32,
}

#[spacetimedb::table(name = next_positions, public)]
pub struct NextPosition {
    #[primary_key]
    entity_id: i32,
    x: i32,
    y: i32,
}

#[spacetimedb::reducer]
pub fn seed(ctx: &ReducerContext) {
    ctx.db.entities().insert(Entity { id: 1 });
    ctx.db.entities().insert(Entity { id: 2 });
    ctx.db.positions().insert(Position { entity_id: 1, x: 0, y: 0 });
    ctx.db.positions().insert(Position { entity_id: 2, x: 10, y: 0 });
    ctx.db.velocities().insert(Velocity { entity_id: 1, vx: 1, vy: 0 });
    ctx.db.velocities().insert(Velocity { entity_id: 2, vx: -2, vy: 3 });
}

#[spacetimedb::reducer]
pub fn step(ctx: &ReducerContext) {
    for pos in ctx.db.positions().iter() {
        if let Some(vel) = ctx.db.velocities().entity_id().find(&pos.entity_id) {
            let new_x = pos.x + vel.vx;
            let new_y = pos.y + vel.vy;
            let next_pos = NextPosition { entity_id: pos.entity_id, x: new_x, y: new_y };
            if ctx.db.next_positions().entity_id().find(&next_pos.entity_id).is_some() {
                ctx.db.next_positions().entity_id().update(next_pos);
            } else {
                ctx.db.next_positions().insert(next_pos);
            }
        }
    }
}

