import { schema, table, t } from 'spacetimedb/server';

const entity = table(
  { public: true },
  {
    id: t.i32().primaryKey().autoInc(),
  }
);

const position = table(
  { public: true },
  {
    entityId: t.i32().primaryKey(),
    x: t.i32(),
    y: t.i32(),
  }
);

const velocity = table(
  { public: true },
  {
    entityId: t.i32().primaryKey(),
    vx: t.i32(),
    vy: t.i32(),
  }
);

const nextPosition = table(
  { public: true },
  {
    entityId: t.i32().primaryKey(),
    x: t.i32(),
    y: t.i32(),
  }
);

const spacetimedb = schema({ entity, position, velocity, nextPosition });
export default spacetimedb;

export const seed = spacetimedb.reducer((ctx) => {
  const entity1 = ctx.db.entity.insert({ id: 0 });
  const entity2 = ctx.db.entity.insert({ id: 0 });
  ctx.db.position.insert({ entityId: entity1.id, x: 0, y: 0 });
  ctx.db.velocity.insert({ entityId: entity1.id, vx: 1, vy: 0 });
  ctx.db.position.insert({ entityId: entity2.id, x: 10, y: 0 });
  ctx.db.velocity.insert({ entityId: entity2.id, vx: -2, vy: 3 });
});

export const step = spacetimedb.reducer((ctx) => {
  for (const pos of ctx.db.position.iter()) {
    const vel = ctx.db.velocity.entityId.find(pos.entityId);
    if (vel) {
      const newX = pos.x + vel.vx;
      const newY = pos.y + vel.vy;
      const existing = ctx.db.nextPosition.entityId.find(pos.entityId);
      if (existing) {
        ctx.db.nextPosition.entityId.update({ ...existing, x: newX, y: newY });
      } else {
        ctx.db.nextPosition.insert({ entityId: pos.entityId, x: newX, y: newY });
      }
    }
  }
});

