import { schema, table, t } from 'spacetimedb/server';

const entity = table(
  { },
  {
    id: t.i32().primaryKey(),
  }
);

const position = table(
  { },
  {
    entityId: t.i32().primaryKey(),
    x: t.i32(),
    y: t.i32(),
  }
);

const velocity = table(
  { },
  {
    entityId: t.i32().primaryKey(),
    vx: t.i32(),
    vy: t.i32(),
  }
);

const nextPosition = table(
  { },
  {
    entityId: t.i32().primaryKey(),
    x: t.i32(),
    y: t.i32(),
  }
);

export const spacetimedb = schema({ entity, position, velocity, nextPosition });
export default spacetimedb;

export const seed = spacetimedb.reducer((ctx) => {
  // Insert Entity 1
  ctx.db.entity.id.insert({ id: 1 });
  ctx.db.position.entityId.insert({ entityId: 1, x: 0, y: 0 });
  ctx.db.velocity.entityId.insert({ entityId: 1, vx: 1, vy: 0 });

  // Insert Entity 2
  ctx.db.entity.id.insert({ id: 2 });
  ctx.db.position.entityId.insert({ entityId: 2, x: 10, y: 0 });
  ctx.db.velocity.entityId.insert({ entityId: 2, vx: -2, vy: 3 });
});

export const step = spacetimedb.reducer((ctx) => {
  for (const pos of ctx.db.position.iter()) {
    const vel = ctx.db.velocity.entityId.find(pos.entityId);
    if (!vel) continue;
    const nx = pos.x + vel.vx;
    const ny = pos.y + vel.vy;
    const existing = ctx.db.nextPosition.entityId.find(pos.entityId);
    if (existing) {
      ctx.db.nextPosition.entityId.update({ ...existing, x: nx, y: ny });
    } else {
      ctx.db.nextPosition.entityId.insert({ entityId: pos.entityId, x: nx, y: ny });
    }
  }
});

