  {
    entityId: t.i32().primaryKey(),
    vx: t.i32(),
    vy: t.i32(),
  }
);

const nextPosition = table(
  { name: 'nextPosition', public: true },
  {
    entityId: t.i32().primaryKey(),
    x: t.i32(),
    y: t.i32(),
  }
);

