import { schema, table, t } from 'spacetimedb/server';

export const entity = table({ name: 'entity' }, {
  id: t.i32().primaryKey(),
});

export const position = table({ name: 'position' }, {
  entityId: t.i32().primaryKey(),
  x: t.i32(),
  y: t.i32(),
});

export const velocity = table({ name: 'velocity' }, {
  entityId: t.i32().primaryKey(),
  vx: t.i32(),
  vy: t.i32(),
});

export const nextPosition = table({ name: 'nextPosition' }, {
  entityId: t.i32().primaryKey(),
  x: t.i32(),
  y: t.i32(),
});

export const spacetimedb = schema(entity, position, velocity, nextPosition);

export const seed = spacetimedb.reducer('seed', {}, (ctx) => {
  ctx.db.entity.insert({ id: 1 });
  ctx.db.position.insert({ entityId: 1, x: 0, y: 0 });
  ctx.db.velocity.insert({ entityId: 1, vx: 1, vy: 0 });

  ctx.db.entity.insert({ id: 2 });
  ctx.db.position.insert({ entityId: 2, x: 10, y: 0 });
  ctx.db.velocity.insert({ entityId: 2, vx: -2, vy: 3 });
});

export const step = spacetimedb.reducer('step', {}, (ctx) => {
  for (const pos of ctx.db.position.iter()) {
    const vel = ctx.db.velocity.entityId.find(pos.entityId);
    if (!vel) continue;
    const x = pos.x + vel.vx;
    const y = pos.y + vel.vy;

    const existing = ctx.db.nextPosition.entityId.find(pos.entityId);
    if (existing) {
      ctx.db.nextPosition.entityId.update({ ...existing, x, y });
    } else {
      ctx.db.nextPosition.insert({ entityId: pos.entityId, x, y });
    }
  }
});

